class ApiConfig {
    enum Environment {
        DEVELOPMENT,
        STAGING,
        PRODUCTION
    }

    static Environment currentEnvironment = Environment.DEVELOPMENT;

    static String getBaseUrl() {
        switch (currentEnvironment) {
            case STAGING:
                return "https://staging.api.example.com/";
            case PRODUCTION:
                return "https://api.example.com/";
            case DEVELOPMENT:
            default:
                return "https://dev.api.example.com/";
        }
    }
}

class ApiClient {
    private static volatile ApiService apiService;

    static void init(Context context) {
        if (apiService != null) return;

        synchronized (ApiClient.class) {
            if (apiService != null) return;

            HttpLoggingInterceptor loggingInterceptor = new HttpLoggingInterceptor();
            loggingInterceptor.setLevel(HttpLoggingInterceptor.Level.BODY);

            Interceptor commonHeadersInterceptor = new Interceptor() {
                @NonNull
                @Override
                public Response intercept(@NonNull Chain chain) throws IOException {
                    return chain.proceed(chain.request().newBuilder()
                            .addHeader("Accept", "application/json")
                            .addHeader("Content-Type", "application/json")
                            .build());
                }
            };

            OkHttpClient okHttpClient = new OkHttpClient.Builder()
                    .connectTimeout(15, TimeUnit.SECONDS)
                    .readTimeout(15, TimeUnit.SECONDS)
                    .writeTimeout(15, TimeUnit.SECONDS)
                    .addInterceptor(commonHeadersInterceptor)
                    .addInterceptor(loggingInterceptor)
                    .build();

            Retrofit retrofit = new Retrofit.Builder()
                    .baseUrl(ApiConfig.getBaseUrl())
                    .client(okHttpClient)
                    .addConverterFactory(GsonConverterFactory.create())
                    .build();

            apiService = retrofit.create(ApiService.class);
        }
    }

    static ApiService getApiService() {
        if (apiService == null) {
            throw new IllegalStateException("ApiClient not initialized");
        }
        return apiService;
    }
}

interface ApiService {
    @GET("users")
    Call<List<User>> getUsers();
}

class User {
    public int id;
    public String name;
    public String email;
}

class UserRepository {
    private final ApiService apiService;

    UserRepository() {
        this.apiService = ApiClient.getApiService();
    }

    void fetchUsers(Callback<List<User>> callback) {
        apiService.getUsers().enqueue(callback);
    }
}

public class MainActivity extends AppCompatActivity {
    private TextView textView;
    private UserRepository userRepository;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        textView = new TextView(this);
        textView.setPadding(32, 32, 32, 32);
        textView.setText("Loading users...");
        setContentView(textView);

        userRepository = new UserRepository();
        loadUsers();
    }

    private void loadUsers() {
        userRepository.fetchUsers(new Callback<List<User>>() {
            @Override
            public void onResponse(@NonNull Call<List<User>> call, @NonNull retrofit2.Response<List<User>> response) {
                if (response.isSuccessful() && response.body() != null) {
                    StringBuilder builder = new StringBuilder();
                    for (User user : response.body()) {
                        builder.append("ID: ").append(user.id).append("\n")
                                .append("Name: ").append(user.name).append("\n")
                                .append("Email: ").append(user.email).append("\n\n");
                    }
                    textView.setText(builder.toString());
                } else {
                    textView.setText("Failed to load users: " + response.code());
                }
            }

            @Override
            public void onFailure(@NonNull Call<List<User>> call, @NonNull Throwable t) {
                textView.setText("Error: " + t.getMessage());
            }
        });
    }
}